#include <WiFi.h>
#include <PubSubClient.h>
#include <ArduinoJson.h>
#include <EEPROM.h>

// Wi-Fi Configuration
#define LED_PIN {{.ledPin}}
#define PUBLISH_INTERVAL {{.publishInterval}} * 1000 // Convert to milliseconds
#define AGGREGATION_WINDOW {{.aggregationWindow}} * 1000
#define BUFFER_SIZE {{.bufferSize}}
#define MAX_SENSORS 8

// MQTT Configuration
const char* wifiSSID = "{{.wifiSSID}}";
const char* wifiPassword = "{{.wifiPassword}}";
const char* mqttBroker = "{{.mqttBroker}}";
const int mqttPort = {{.mqttPort}};
const char* mqttUsername = "{{.mqttUsername}}";
const char* mqttPassword = "{{.mqttPassword}}";
const char* deviceId = "{{.deviceId}}";
const char* baseTopic = "{{.baseTopic}}";
const bool enableRetained = {{.enableRetained}};

// Global variables
WiFiClient wifiClient;
PubSubClient mqttClient(wifiClient);

// Sensor configuration
struct SensorConfig {
  int pin;
  String name;
  String unit;
  float multiplier;
  float values[10]; // Circular buffer for aggregation
  int valueIndex;
  float sum;
  float min;
  float max;
  int count;
};

SensorConfig sensors[MAX_SENSORS];
int sensorCount = 0;

// Data buffering
struct SensorReading {
  unsigned long timestamp;
  String sensorName;
  float value;
  String unit;
};

SensorReading buffer[BUFFER_SIZE];
int bufferHead = 0;
int bufferTail = 0;
int bufferCount = 0;

// Status tracking
enum BridgeStatus {
  DISCONNECTED,
  CONNECTING_WIFI,
  CONNECTING_MQTT,
  CONNECTED,
  ERROR
};

BridgeStatus currentStatus = DISCONNECTED;
unsigned long lastPublishTime = 0;
unsigned long lastAggregationTime = 0;

// Function prototypes
void setupWiFi();
void setupMQTT();
void connectToWiFi();
void connectToMQTT();
void initializeSensors();
float readSensor(int pin);
void updateAggregations();
void publishSensorData();
void publishBufferedData();
void bufferSensorReading(const String& sensorName, float value, const String& unit);
void mqttCallback(char* topic, byte* payload, unsigned int length);
void updateStatusLED();
void sendStatusUpdate();
bool publishMessage(const char* topic, const char* payload, bool retained = false);

void setup() {
  Serial.begin(115200);
  Serial.println("MQTT Bridge for Sensor Data Aggregation Starting...");

  // Initialize pins
  pinMode(LED_PIN, OUTPUT);
  digitalWrite(LED_PIN, LOW);

  // Initialize sensors
  initializeSensors();

  Serial.print("Initialized ");
  Serial.print(sensorCount);
  Serial.println(" sensors");

  // Setup Wi-Fi
  setupWiFi();

  // Setup MQTT
  setupMQTT();

  Serial.println("Setup completed!");
  Serial.print("Device ID: ");
  Serial.println(deviceId);
  Serial.print("Base Topic: ");
  Serial.println(baseTopic);
  Serial.println("Bridge ready for data aggregation...");
}

void loop() {
  // Handle MQTT connection
  if (!mqttClient.connected()) {
    if (currentStatus == CONNECTED) {
      Serial.println("MQTT connection lost");
      currentStatus = DISCONNECTED;
    }

    if (currentStatus == DISCONNECTED) {
      connectToWiFi();
      connectToMQTT();
    }
  } else {
    mqttClient.loop();
  }

  // Update sensor readings and aggregations
  updateAggregations();

  // Publish data at intervals
  unsigned long currentTime = millis();
  if (currentTime - lastPublishTime >= PUBLISH_INTERVAL) {
    if (mqttClient.connected()) {
      publishSensorData();
      lastPublishTime = currentTime;
    }
  }

  updateStatusLED();
  delay(100);
}

void setupWiFi() {
  Serial.print("Connecting to Wi-Fi: ");
  Serial.println(wifiSSID);

  currentStatus = CONNECTING_WIFI;

  WiFi.begin(wifiSSID, wifiPassword);

  int attempts = 0;
  while (WiFi.status() != WL_CONNECTED && attempts < 30) {
    delay(500);
    Serial.print(".");
    attempts++;
  }

  if (WiFi.status() == WL_CONNECTED) {
    Serial.println("\nWi-Fi connected!");
    Serial.print("IP address: ");
    Serial.println(WiFi.localIP());
  } else {
    Serial.println("\nWi-Fi connection failed!");
    currentStatus = ERROR;
  }
}

void setupMQTT() {
  mqttClient.setServer(mqttBroker, mqttPort);
  mqttClient.setCallback(mqttCallback);

  // Set MQTT client ID
  String clientId = String(deviceId) + "-" + String(random(0xffff), HEX);
  mqttClient.setClientId(clientId.c_str());

  Serial.print("MQTT broker: ");
  Serial.print(mqttBroker);
  Serial.print(":");
  Serial.println(mqttPort);
}

void connectToMQTT() {
  Serial.println("Connecting to MQTT broker...");

  currentStatus = CONNECTING_MQTT;

  bool connected = false;
  if (strlen(mqttUsername) > 0) {
    connected = mqttClient.connect(deviceId, mqttUsername, mqttPassword);
  } else {
    connected = mqttClient.connect(deviceId);
  }

  if (connected) {
    Serial.println("MQTT connected!");

    // Subscribe to configuration topics
    String configTopic = String(baseTopic) + "/" + String(deviceId) + "/config/+";
    mqttClient.subscribe(configTopic.c_str());

    // Publish connection status
    sendStatusUpdate();

    // Publish any buffered data
    if ({{.enableBuffering}}) {
      publishBufferedData();
    }

    currentStatus = CONNECTED;
  } else {
    Serial.println("MQTT connection failed!");
    currentStatus = ERROR;
  }
}

void initializeSensors() {
  // Initialize sensor configurations
  {{#each .sensorPins}}
  if (sensorCount < MAX_SENSORS) {
    sensors[sensorCount].pin = {{pin}};
    sensors[sensorCount].name = "{{name}}";
    sensors[sensorCount].unit = "{{unit}}";
    sensors[sensorCount].multiplier = {{multiplier}};

    // Initialize aggregation buffers
    sensors[sensorCount].valueIndex = 0;
    sensors[sensorCount].sum = 0;
    sensors[sensorCount].min = 999999;
    sensors[sensorCount].max = -999999;
    sensors[sensorCount].count = 0;

    // Clear value buffer
    for (int i = 0; i < 10; i++) {
      sensors[sensorCount].values[i] = 0;
    }

    sensorCount++;
  }
  {{/each}}

  // Initialize buffer
  bufferHead = 0;
  bufferTail = 0;
  bufferCount = 0;
}

float readSensor(int pin) {
  // Read analog sensor value
  int rawValue = analogRead(pin);

  // Convert to voltage (assuming 3.3V reference)
  float voltage = (rawValue / 4095.0) * 3.3;

  return voltage;
}

void updateAggregations() {
  unsigned long currentTime = millis();

  // Update aggregations at regular intervals
  if (currentTime - lastAggregationTime >= AGGREGATION_WINDOW) {
    {{#if .enableAggregation}}
    for (int i = 0; i < sensorCount; i++) {
      float currentValue = readSensor(sensors[i].pin) * sensors[i].multiplier;

      // Add to circular buffer
      sensors[i].values[sensors[i].valueIndex] = currentValue;
      sensors[i].valueIndex = (sensors[i].valueIndex + 1) % 10;

      // Update statistics
      sensors[i].sum += currentValue;
      sensors[i].count++;

      if (currentValue < sensors[i].min) {
        sensors[i].min = currentValue;
      }
      if (currentValue > sensors[i].max) {
        sensors[i].max = currentValue;
      }
    }
    {{/if}}

    lastAggregationTime = currentTime;
  }
}

void publishSensorData() {
  JsonDocument doc;
  JsonObject root = doc.to<JsonObject>();

  root["deviceId"] = deviceId;
  root["timestamp"] = millis();
  root["wifiRSSI"] = WiFi.RSSI();

  JsonObject sensorsObj = root.createNestedObject("sensors");

  for (int i = 0; i < sensorCount; i++) {
    JsonObject sensorObj = sensorsObj.createNestedObject(sensors[i].name);

    float currentValue = readSensor(sensors[i].pin) * sensors[i].multiplier;

    {{#if .enableAggregation}}
    // Calculate average from buffer
    float sum = 0;
    for (int j = 0; j < 10; j++) {
      sum += sensors[i].values[j];
    }
    float average = sum / 10.0;

    sensorObj["current"] = currentValue;
    sensorObj["average"] = average;
    sensorObj["min"] = sensors[i].min;
    sensorObj["max"] = sensors[i].max;
    sensorObj["count"] = sensors[i].count;
    sensorObj["unit"] = sensors[i].unit;

    // Reset aggregation for next window
    sensors[i].sum = 0;
    sensors[i].min = 999999;
    sensors[i].max = -999999;
    sensors[i].count = 0;
    {{else}}
    // Publish current value only
    sensorObj["value"] = currentValue;
    sensorObj["unit"] = sensors[i].unit;
    {{/if}}
  }

  // Buffer reading if enabled and offline
  if ({{.enableBuffering}} && !mqttClient.connected()) {
    for (int i = 0; i < sensorCount; i++) {
      float value = readSensor(sensors[i].pin) * sensors[i].multiplier;
      bufferSensorReading(sensors[i].name, value, sensors[i].unit);
    }
    return;
  }

  // Publish to MQTT
  String topic = String(baseTopic) + "/" + String(deviceId) + "/data";
  String payload;
  serializeJson(doc, payload);

  publishMessage(topic.c_str(), payload.c_str(), enableRetained);

  Serial.print("Published sensor data: ");
  Serial.println(payload);
}

void publishBufferedData() {
  if (bufferCount == 0) {
    return;
  }

  Serial.print("Publishing ");
  Serial.print(bufferCount);
  Serial.println(" buffered readings");

  while (bufferCount > 0) {
    SensorReading reading = buffer[bufferTail];

    JsonDocument doc;
    doc["deviceId"] = deviceId;
    doc["timestamp"] = reading.timestamp;
    doc["sensorName"] = reading.sensorName;
    doc["value"] = reading.value;
    doc["unit"] = reading.unit;
    doc["buffered"] = true;

    String topic = String(baseTopic) + "/" + String(deviceId) + "/data";
    String payload;
    serializeJson(doc, payload);

    publishMessage(topic.c_str(), payload.c_str(), false);

    bufferTail = (bufferTail + 1) % BUFFER_SIZE;
    bufferCount--;

    delay(100); // Small delay between messages
  }

  Serial.println("Buffered data published");
}

void bufferSensorReading(const String& sensorName, float value, const String& unit) {
  if (bufferCount >= BUFFER_SIZE) {
    // Buffer is full, remove oldest
    bufferTail = (bufferTail + 1) % BUFFER_SIZE;
    bufferCount--;
  }

  SensorReading reading;
  reading.timestamp = millis();
  reading.sensorName = sensorName;
  reading.value = value;
  reading.unit = unit;

  buffer[bufferHead] = reading;
  bufferHead = (bufferHead + 1) % BUFFER_SIZE;
  bufferCount++;
}

void mqttCallback(char* topic, byte* payload, unsigned int length) {
  Serial.print("MQTT message received [topic: ");
  Serial.print(topic);
  Serial.print("] ");

  // Convert payload to string
  String message = "";
  for (int i = 0; i < length; i++) {
    message += (char)payload[i];
  }
  Serial.println(message);

  // Handle configuration commands
  String topicStr = String(topic);
  if (topicStr.startsWith(String(baseTopic) + "/" + String(deviceId) + "/config/")) {
    String configType = topicStr.substring(String(baseTopic).length() + String(deviceId).length() + 9);

    if (configType == "interval") {
      // Update publish interval
      JsonDocument doc;
      DeserializationError error = deserializeJson(doc, message);

      if (!error && doc.containsKey("interval")) {
        int newInterval = doc["interval"];
        if (newInterval >= 1 && newInterval <= 3600) {
          Serial.print("Updating publish interval to: ");
          Serial.println(newInterval);
          // Note: In a real implementation, you would update the global variable
        }
      }
    } else if (configType == "sensors") {
      // Update sensor configuration
      JsonDocument doc;
      DeserializationError error = deserializeJson(doc, message);

      if (!error && doc.containsKey("sensors")) {
        Serial.println("Updating sensor configuration");
        // Note: In a real implementation, you would reinitialize sensors
      }
    }
  }
}

void updateStatusLED() {
  static unsigned long lastBlinkTime = 0;
  static bool ledState = false;

  switch (currentStatus) {
    case CONNECTED:
      digitalWrite(LED_PIN, HIGH); // Solid on when connected
      break;

    case CONNECTING_WIFI:
    case CONNECTING_MQTT:
      // Slow blink when connecting
      if (millis() - lastBlinkTime > 500) {
        ledState = !ledState;
        digitalWrite(LED_PIN, ledState);
        lastBlinkTime = millis();
      }
      break;

    case ERROR:
      // Fast blink when error
      if (millis() - lastBlinkTime > 200) {
        ledState = !ledState;
        digitalWrite(LED_PIN, ledState);
        lastBlinkTime = millis();
      }
      break;

    default:
      digitalWrite(LED_PIN, LOW); // Off when disconnected
      break;
  }
}

void sendStatusUpdate() {
  JsonDocument doc;
  doc["deviceId"] = deviceId;
  doc["status"] = "online";
  doc["timestamp"] = millis();
  doc["ip"] = WiFi.localIP().toString();
  doc["wifiRSSI"] = WiFi.RSSI();
  doc["sensorCount"] = sensorCount;
  doc["bufferCount"] = bufferCount;

  String topic = String(baseTopic) + "/" + String(deviceId) + "/status";
  String payload;
  serializeJson(doc, payload);

  publishMessage(topic.c_str(), payload.c_str(), true); // Retained status

  Serial.print("Status update published: ");
  Serial.println(payload);
}

bool publishMessage(const char* topic, const char* payload, bool retained) {
  bool success = mqttClient.publish(topic, payload, retained);

  if (success) {
    Serial.print("Message published to ");
    Serial.print(topic);
    Serial.print(": ");
    Serial.println(payload);
  } else {
    Serial.print("Failed to publish to ");
    Serial.println(topic);
  }

  return success;
}
